"use client";

import { useEffect, useState, useRef } from "react";
import { motion, useScroll, useSpring } from "framer-motion";
import TimelineCard from "./TimelineCard";
import { ChevronLeft, ChevronRight, Home } from "lucide-react";
import Link from "next/link";

interface BiblicalEvent {
  id: string;
  title: string;
  description: string;
  verse: string;
  date: string;
  year: number;
  category: string;
}

export default function TimelineContainer() {
  const [events, setEvents] = useState<BiblicalEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollXProgress } = useScroll({ container: containerRef });
  const scaleX = useSpring(scrollXProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  useEffect(() => {
    async function fetchEvents() {
      try {
        const res = await fetch("/api/events");
        const data = await res.json();
        setEvents(data);
      } catch (error) {
        console.error("Failed to fetch events", error);
      } finally {
        setLoading(false);
      }
    }
    fetchEvents();
  }, []);

  const scroll = (direction: "left" | "right") => {
    if (containerRef.current) {
      const scrollAmount = window.innerWidth * 0.8;
      containerRef.current.scrollBy({
        left: direction === "left" ? -scrollAmount : scrollAmount,
        behavior: "smooth"
      });
    }
  };

  if (loading) {
    return (
      <div className="flex-1 flex items-center justify-center bg-canvas">
        <motion.div 
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          className="w-16 h-16 border-4 border-black border-t-intent-action"
        />
      </div>
    );
  }

  return (
    <div className="relative flex-1 flex flex-col bg-canvas overflow-hidden">
      {/* Navigation Bar */}
      <nav className="fixed top-0 left-0 right-0 z-50 p-6 flex justify-between items-center bg-canvas/80 backdrop-blur-sm border-b-structure border-black">
        <Link href="/" className="btn-secondary flex items-center gap-2 bg-white">
          <Home className="w-5 h-5" />
          <span className="hidden md:inline">INICIO</span>
        </Link>
        <div className="flex gap-4">
          <button 
            onClick={() => scroll("left")}
            className="btn-secondary bg-white p-2"
            aria-label="Desplazar a la izquierda"
          >
            <ChevronLeft className="w-6 h-6" />
          </button>
          <button 
            onClick={() => scroll("right")}
            className="btn-secondary bg-white p-2"
            aria-label="Desplazar a la derecha"
          >
            <ChevronRight className="w-6 h-6" />
          </button>
        </div>
      </nav>

      {/* Progress Bar */}
      <motion.div 
        className="fixed top-[88px] left-0 right-0 h-2 bg-intent-action z-40 origin-left"
        style={{ scaleX }}
      />

      {/* Timeline Scrollable Area */}
      <div 
        ref={containerRef}
        className="flex-1 overflow-x-auto overflow-y-hidden snap-x snap-mandatory flex items-center px-[10vw] gap-[5vw] no-scrollbar"
      >
        {events.map((event, index) => (
          <TimelineCard key={event.id} event={event} index={index} />
        ))}
      </div>

      {/* Background Text Decor */}
      <div className="fixed bottom-0 left-0 right-0 -z-10 opacity-[0.03] select-none pointer-events-none">
        <h2 className="text-[20vw] leading-none font-black text-black whitespace-nowrap">
          CHRONOS BIBLICOS
        </h2>
      </div>
    </div>
  );
}
