"use client";

import { motion } from "framer-motion";
import { Book, Quote } from "lucide-react";

interface BiblicalEvent {
  id: string;
  title: string;
  description: string;
  verse: string;
  date: string;
  year: number;
  category: string;
}

interface TimelineCardProps {
  event: BiblicalEvent;
  index: number;
}

export default function TimelineCard({ event, index }: TimelineCardProps) {
  return (
    <motion.article 
      initial={{ y: 50, opacity: 0 }}
      whileInView={{ y: 0, opacity: 1 }}
      transition={{ delay: index * 0.1 }}
      viewport={{ once: true }}
      className="snap-center flex-shrink-0 w-[85vw] md:w-[60vw] lg:w-[45vw] h-[70vh] max-h-[800px] flex flex-col gap-6"
    >
      {/* PHASE 1: ATTENTION (Date & Title) */}
      <header data-aida="attention" className="flex flex-col gap-2">
        <span className="text-4xl md:text-6xl font-black bg-intent-action inline-block self-start px-4 py-2 border-structure border-black shadow-hard">
          {event.date}
        </span>
        <h2 className="text-5xl md:text-7xl lg:text-8xl leading-[0.9] text-text-main break-words">
          {event.title}
        </h2>
      </header>

      {/* PHASE 2: INTEREST (Description) */}
      <section 
        data-aida="interest"
        className="flex-1 flex flex-col gap-4 bg-white border-structure border-black shadow-hard p-8 overflow-y-auto"
      >
        <div className="flex items-center gap-2 text-intent-attention font-bold uppercase tracking-wider text-sm">
          <Book className="w-4 h-4" />
          {event.category}
        </div>
        <p className="text-xl md:text-2xl leading-relaxed text-text-main/80">
          {event.description}
        </p>

        {/* PHASE 3: DESIRE (Verse Quote) */}
        <blockquote 
          data-aida="desire"
          className="mt-auto p-6 bg-canvas border-l-8 border-intent-attention italic flex flex-col gap-3"
        >
          <Quote className="w-8 h-8 text-intent-attention opacity-30" />
          <p className="text-lg md:text-xl font-medium">"{event.verse}"</p>
          <cite className="not-italic font-bold text-sm uppercase">— REFERENCIA BÍBLICA</cite>
        </blockquote>
      </section>

      {/* PHASE 4: ACTION (Navigation Guide) */}
      <footer 
        data-aida="action"
        className="flex justify-between items-center text-xs font-black tracking-widest uppercase opacity-40"
      >
        <span>Desliza para continuar</span>
        <span>{index + 1} / EVENTOS</span>
      </footer>
    </motion.article>
  );
}
